from pathlib import Path
import csv
import os
import re
import shutil
from decimal import Decimal, ROUND_HALF_UP

import fitz
from PIL import Image
import pytesseract

DOCS = Path('/app/documents')
INV = Path('/app/invoices')
OTH = Path('/app/other')
INV.mkdir(exist_ok=True)
OTH.mkdir(exist_ok=True)

NUM_RE = re.compile(r'(?<!\d)(?:\d{1,3}(?:[ ,]\d{3})+|\d+)(?:[.,]\d+)?(?!\d)')
TWOPL = Decimal('0.01')


def extract_text(path: Path) -> str:
    if path.suffix.lower() == '.pdf':
        with fitz.open(path) as doc:
            return '\n'.join(page.get_text() for page in doc)
    img = Image.open(path)
    try:
        return pytesseract.image_to_string(img, config='--psm 6')
    finally:
        try:
            img.close()
        except Exception:
            pass


def norm_num(token: str):
    s = token.strip()
    s = s.replace('$', '').replace('€', '').replace('£', '').replace('USD', '').replace('usd', '')
    s = re.sub(r'\s+', ' ', s).strip()
    if not s:
        return None
    # spaces are often thousands separators in OCR'd invoices
    s = s.replace(' ', '')
    if ',' in s and '.' in s:
        if s.rfind(',') > s.rfind('.'):
            s = s.replace('.', '')
            s = s.replace(',', '.')
        else:
            s = s.replace(',', '')
    elif ',' in s:
        parts = s.split(',')
        if len(parts[-1]) in (1, 2):
            s = ''.join(parts[:-1]) + '.' + parts[-1]
        else:
            s = ''.join(parts)
    try:
        return Decimal(s)
    except Exception:
        return None


def line_numbers(line: str):
    vals = []
    for m in NUM_RE.finditer(line):
        val = norm_num(m.group(0))
        if val is not None:
            vals.append(val)
    return vals


def is_invoice(text: str) -> bool:
    low = text.lower()
    strong = [
        'invoice no', 'invoice number', 'date due', 'bill to', 'amount due',
        'grand total', 'totalprice', 'gross worth', 'vat [%]', 'invoice order id'
    ]
    return any(tok in low for tok in strong) or (('invoice' in low) and ('total' in low or 'bill to' in low))


def extract_amounts(text: str):
    lines = [ln.strip() for ln in text.splitlines() if ln.strip()]
    total_candidates = {}
    amount_due = None
    vat_amount = None

    for i, line in enumerate(lines):
        low = line.lower()
        nxt = lines[i + 1].strip() if i + 1 < len(lines) else ''

        if 'totalprice' in low:
            nums = line_numbers(line)
            if nums:
                total_candidates['total'] = nums[-1]
            else:
                nums = line_numbers(nxt)
                if nums:
                    total_candidates['total'] = nums[-1]
            continue

        if 'grand total' in low or re.search(r'\btotal\b', low):
            if 'subtotal' in low:
                continue
            nums = line_numbers(line)
            if 'gross worth' in low and len(nums) >= 2:
                # header-like line, skip
                pass
            elif nums:
                if 'amount due' in low:
                    amount_due = nums[-1]
                else:
                    total_candidates['total'] = nums[-1]
                    if vat_amount is None and len(nums) >= 3:
                        vat_amount = nums[-2]
            elif nxt:
                nxt_nums = line_numbers(nxt)
                if nxt_nums:
                    total_candidates['total'] = nxt_nums[-1]
            # continue scanning, since amount due may also exist

        if 'amount due' in low:
            nums = line_numbers(line)
            if nums:
                amount_due = nums[-1]
            elif nxt:
                nxt_nums = line_numbers(nxt)
                if nxt_nums:
                    amount_due = nxt_nums[-1]

        if vat_amount is None and re.search(r'\b(vat|gst|tax)\b', low):
            nums = line_numbers(line)
            # Exclude tax id lines and percentage-only headers
            if ('tax id' in low) or ('vat [%]' in low and len(nums) < 2):
                pass
            else:
                if len(nums) >= 2 and ('gross worth' in low or low.startswith('total')):
                    vat_amount = nums[-2]
                elif len(nums) == 1 and '%' not in line:
                    vat_amount = nums[-1]
                elif nxt:
                    nxt_nums = line_numbers(nxt)
                    if len(nxt_nums) >= 2:
                        vat_amount = nxt_nums[-2]
                    elif len(nxt_nums) == 1:
                        vat_amount = nxt_nums[-1]

    total_amount = total_candidates.get('total')
    if total_amount is None:
        total_amount = amount_due
    # Special rule: if both exist and differ, keep Total (already preferred)
    if total_amount is None:
        total_amount = Decimal('0')
    if vat_amount is None:
        vat_amount = Decimal('0')
    return total_amount, vat_amount


def fmt(d: Decimal) -> str:
    d = d.quantize(TWOPL, rounding=ROUND_HALF_UP)
    return format(d, 'f')

invoice_rows = []
for path in sorted(DOCS.iterdir()):
    if not path.is_file():
        continue
    text = extract_text(path)
    dest_dir = INV if is_invoice(text) else OTH
    if dest_dir is INV:
        total_amount, vat_amount = extract_amounts(text)
        invoice_rows.append((path.name, total_amount, vat_amount))
    shutil.move(str(path), str(dest_dir / path.name))

invoice_rows.sort(key=lambda x: x[0])
total_total = sum((row[1] for row in invoice_rows), Decimal('0'))
total_vat = sum((row[2] for row in invoice_rows), Decimal('0'))

with (INV / 'summary.csv').open('w', newline='') as f:
    writer = csv.writer(f)
    writer.writerow(['filename', 'total_amount', 'vat_amount'])
    for name, total_amount, vat_amount in invoice_rows:
        writer.writerow([name, fmt(total_amount), fmt(vat_amount)])
    writer.writerow(['total', fmt(total_total), fmt(total_vat)])

print('processed', len(invoice_rows), 'invoices')
for row in invoice_rows:
    print(row[0], fmt(row[1]), fmt(row[2]))
print('totals', fmt(total_total), fmt(total_vat))
